For the events table with the given workload, here is a concrete indexing strategy:

-- Primary key is already indexed (B-tree by default)

-- 1. Composite B-tree for fetching latest 100 events per user in date range
CREATE INDEX idx_events_user_created ON events (user_id, created_at DESC);

-- 2. Composite B-tree for counting by user and type within date window
CREATE INDEX idx_events_user_type_created ON events (user_id, event_type, created_at);

-- 3. Hash index for equality filter on event_type (if high-cardinality, consider B-tree instead)
CREATE INDEX idx_events_type_hash ON events USING hash (event_type);

-- 4. Partial index for retrieving most recent event per user (hot data)
CREATE INDEX idx_events_recent_user ON events (user_id, created_at DESC)
WHERE created_at > NOW() - INTERVAL '30 days';

