async function reserve(itemId, userId, qty){
  const lockKey = `lock:reserve:${itemId}:${userId}`;
  if (!await acquireLock(lockKey, 10000)) throw new Error('Lock failed');
  try {
    await mongo.stockDecrement(itemId, qty);
    await cassandra.logEvent({id: itemId, user: userId, qty, t: Date.now()});
    await dynamo.upsertSummary({city: 'global', itemId, delta: -qty});
  } finally {
    await releaseLock(lockKey);
  }
}
```

## Why This Is Asked
