## Code Example
```javascript
// Write path (pseudo)
async function onView(userId, pid) {
  const ts = Date.now();
  await cassandra.insert('view_event', {userId, pid, ts});
  await redis.lpush(`recent:${userId}`, pid);
  await redis.ltrim(`recent:${userId}`, 0, 9);
  await redis.expire(`recent:${userId}`, 7*24*3600);
  await dynamo.update('daily_views', {date: today, pid}, {increment: 1}, {upsert: true});
}

// Read path (fallback)
async function getRecent(userId) {
  let ids = await redis.lrange(`recent:${userId}`, 0, 9);
  if (!ids.length) {
    const events = await cassandra.query('SELECT pid FROM view_event WHERE userId=? ORDER BY ts DESC LIMIT 10', userId);
    ids = events.map(e => e.pid);
    await redis.rpush(`recent:${userId}`, ...ids);
    await redis.expire(`recent:${userId}`, 7*24*3600);
  }
  const products = await mongo.find('products', {_id: {$in: ids}});
  return ids.map(id => products.find(p => p._id === id));
}
```

## Why This Is Asked
This question evaluates candidates on designing distributed data deletion across polyglot persistence architectures—a critical skill for compliance with GDPR, CCPA, and similar regulations. It tests understanding of eventual consistency, cross-store coordination, and the tradeoffs between soft deletes, tombstones, and hard deletes.

## Key Concepts
- **Cross-store consistency**: Coordinating deletes across heterogeneous data stores with different consistency models
- **Idempotence**: Ensuring delete operations can be safely retried without side effects
- **Soft delete vs. tombstones**: MongoDB uses soft deletes (timestamp-based), Cassandra uses tombstones (marked for garbage collection), Redis and DynamoDB use hard deletes
- **Audit logging**: Maintaining an immutable trail of deletion requests for compliance
- **Retention and purge**: Understanding TTL behavior and compaction cycles for data expiration

## Code Example
```javascript
const { v4: uuidv4 } = require('uuid');

async function deleteUser(userId, initiatedBy) {
  const requestId = uuidv4();
  const timestamp = new Date();

  // Idempotency check
  const existingRequest = await auditLog.findOne({ requestId });
  if (existingRequest) {
    return { status: 'already_completed', requestId };
  }

  // Parallel deletes across stores
  const [redisResult, mongoResult, cassandraResult, dynamoResult] = await Promise.all([
    redis.del(`session:${userId}`),
    mongo.updateOne(
      { userId },
      { $set: { deleted_at: timestamp, private_fields: {}, deletion_request_id: requestId } }
    ),
    cassandra.execute('DELETE FROM telemetry WHERE user_id = ?', [userId]),
    dynamodb.deleteItem({
      TableName: 'WeeklySummaries',
      Key: { userId: { S: userId } }
    }).promise()
  ]);

  // Audit log (append-only)
  await auditLog.insertOne({
    requestId,
    userId,
    timestamp,
    initiatedBy,
    stores_affected: ['redis', 'mongodb', 'cassandra', 'dynamodb'],
    status: 'completed'
  });

  return { status: 'completed', requestId };
}

// Read filter example
async function getUserProfile(userId) {
  const user = await mongo.findOne({ userId, deleted_at: null });
  if (!user) return null;
  return user;
}
```

## Additional Considerations
- **Eventual consistency**: Cassandra and DynamoDB may have brief windows where deleted data is still readable. Implement read-your-writes consistency or delay verification.
- **TTL coordination**: Set application-level TTLs that exceed the longest store's garbage collection period to ensure complete deletion.
- **Failure handling**: Use a saga pattern or distributed transaction log to track partial failures and implement compensating actions.

