// Optimistic locking with version check
async function updateDocument(docId: string, changes: any, expectedVersion: number) {
  const result = await db.transaction(async (tx) => {
    const doc = await tx.query.documents.findFirst({
      where: { id: docId, version: expectedVersion }
    });

    if (!doc) {
      throw new Error('Document not found or version mismatch');
    }

    return await tx.update(documents)
      .set({ ...changes, version: expectedVersion + 1 })
      .where({ id: docId });
  });

  return result;
}

// Conflict resolution with retry
async function updateWithRetry(docId: string, changes: any, maxRetries = 3) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const doc = await getDocument(docId);
      return await updateDocument(docId, changes, doc.version);
    } catch (error) {
      if (attempt === maxRetries) throw error;
      await delay(Math.pow(2, attempt) * 100); // Exponential backoff
    }
  }
}
```

