async function transferFunds(fromId: number, toId: number, amount: number) {
  const maxRetries = 3;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    const tx = await db.transaction({ isolationLevel: 'serializable' });

    try {
      // Lock both accounts to prevent concurrent modifications
      const [fromAccount, toAccount] = await Promise.all([
        tx.query('SELECT balance FROM accounts WHERE id = $1 FOR UPDATE', [fromId]),
        tx.query('SELECT balance FROM accounts WHERE id = $1 FOR UPDATE', [toId])
      ]);

      if (fromAccount.balance < amount) {
        await tx.rollback();
        throw new Error('Insufficient funds');
      }

      await Promise.all([
        tx.query('UPDATE accounts SET balance = balance - $1 WHERE id = $2', [amount, fromId]),
        tx.query('UPDATE accounts SET balance = balance + $1 WHERE id = $2', [amount, toId])
      ]);

      await tx.commit();
      return;
    } catch (error) {
      await tx.rollback();
      if (error.code === '40001' && attempt < maxRetries) {
        // Serialization failure, retry with exponential backoff
        await new Promise(resolve => setTimeout(resolve, Math.pow(2, attempt) * 100));
        continue;
      }
      throw error;
    }
  }
}
```

