COMMIT;

-- SERIALIZABLE (prevents lost update)
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
UPDATE Accounts SET balance = balance - 60 WHERE account_id = 1 AND balance >= 60;
COMMIT;

